def total_due(items, tax_rate):
    # Apply quantity first
    subtotal = sum(item["price"] * item.get("quantity", 1) for item in items)

    # If subtotal > 100, apply 10% discount to non-gift-card items only
    if subtotal > 100:
        discount_total = 0
        for item in items:
            if item.get("category") != "gift_card":
                discount_total += item["price"] * item.get("quantity", 1)
        subtotal -= discount_total * 0.1

    return round(subtotal * (1 + tax_rate), 2)
